interface RateLimitConfig {
  capacity: number;      // max tokens (burst capacity)
  refillRate: number;    // tokens per second
  window?: number;       // sliding window in milliseconds
}

interface RateLimitState {
  tokens: number;
  lastRefill: number;
}

class RateLimiter {
  private config: RateLimitConfig;
  private users: Map<string, RateLimitState>;

  constructor(config: RateLimitConfig) {
    this.config = config;
    this.users = new Map();
  }

  private refillTokens(userId: string, now: number): number {
    const state = this.users.get(userId) || {
      tokens: this.config.capacity,
      lastRefill: now,
    };

    const timePassed = (now - state.lastRefill) / 1000; // seconds
    const tokensAdded = timePassed * this.config.refillRate;
    const newTokens = Math.min(
      state.tokens + tokensAdded,
      this.config.capacity
    );

    state.tokens = newTokens;
    state.lastRefill = now;

    this.users.set(userId, state);
    return newTokens;
  }

  isAllowed(userId: string, tokensNeeded: number = 1): boolean {
    const now = Date.now();
    const availableTokens = this.refillTokens(userId, now);

    if (availableTokens >= tokensNeeded) {
      const state = this.users.get(userId)!;
      state.tokens -= tokensNeeded;
      return true;
    }

    return false;
  }
}
```

This implementation calculates elapsed time since the last refill to determine how many tokens to add back, capping at the configured capacity. The `isAllowed` method checks if sufficient tokens exist for the request and deducts them if approved.

